configfiles.configfile:
@CMD_imports@
@CMD_read_inputs@

subsets <- list()
#for $s in $subsets_repeat
subsets[['${s.name}']] <- which(rownames(sce) %in% readLines('$s.feature_file'))
#end for

sce <- scuttle::addPerCellQCMetrics(
    x          = sce,
    subsets    = subsets,
    assay.type = '$assay_type'
)

@CMD_loom_write_outputs@
